388:     // ── LITERAL mode: just append ──
389:     if (s.mode == 1) {
390:         appendSpan(s, ch, 0, 0, flags | 0x02);
391:         return 1;
392:     }
393: 
394:     // ── Check if first char triggers LITERAL mode ──
395:     if (s.len == 0) {
396:         if (lo == 'f' or lo == 'j' or lo == 'w' or lo == 'z') {
397:             enterLiteral(s);
398:             appendSpan(s, ch, 0, 0, flags | 0x02);
399:             return 1;
400:         }
401:         // First char: just append as a regular span
402:         appendSpan(s, ch, 0, 0, flags);
403:         return 1;
404:     }
405: 
406:     // ── dd → đ ──
407:     if (lo == 'd') {
408:         // Look for last 'd' span without modifier
409:         if (s.len > 0) {
410:             const last_idx = s.len - 1;
411:             const last = &s.spans[last_idx];
412:             if (toLower(last.base) == 'd' and last.modifier == 0) {
413:                 // Cancellation: if already đ, undo
414:                 if (last.modifier == 'd') {
415:                     // Already handled above: modifier is 0 here
416:                     unreachable;
417:                 }
418:                 last.modifier = 'd';
419:                 return 1;
420:             }
421:         }
422:         // Regular d consonant
423:         appendSpan(s, ch, 0, 0, flags);
424:         autoFillUO(s);
425:         return 1;
426:     }
427: 
428:     // ── Doubled vowel modifier: aa→â, ee→ê, oo→ô ──
429:     if (lo == 'a' or lo == 'e' or lo == 'o') {
430:         // Check if previous span is the same base vowel with no modifier
431:         if (s.len > 0) {
432:             const last_idx = s.len - 1;
433:             const last = &s.spans[last_idx];
434:             if (toLower(last.base) == lo and last.modifier == 0 and spanIsVowel(last.*)) {
435:                 // Cancellation check: if modifier already equals lo, strip it
436:                 // (can't happen here since modifier == 0)
437:                 last.modifier = lo;
438:                 return 1;
439:             }
440:         }
441:     }
442: 
443:     // ── w modifier ──
444:     if (lo == 'w') {
445:         // Look for target vowel: last a/o/u in the word
446:         var target: ?u8 = null;
447:         var i: u8 = 0;
448:         while (i < s.len) : (i += 1) {
449:             const b = toLower(s.spans[i].base);
450:             if (b == 'a' or b == 'o' or b == 'u') {
451:                 target = i;
452:             }
453:         }
454:         if (target) |ti| {
455:             const sp = &s.spans[ti];
456:             if (sp.modifier == 'w') {
457:                 // Cancellation: same modifier pressed again → enter literal
458:                 enterLiteral(s);
459:                 appendSpan(s, ch, 0, 0, flags | 0x02);
460:                 return 1;
461:             }
462:             if (sp.modifier != 0) {
463:                 // Already has a different modifier, can't apply w
464:                 // Treat w as a regular character → literal
465:                 enterLiteral(s);
466:                 appendSpan(s, ch, 0, 0, flags | 0x02);
467:                 return 1;
468:             }
469:             sp.modifier = 'w';
470:             // Re-apply tone placement since modified vowel changed
471:             const ct = currentTone(s);
472:             if (ct != 0) applyTone(s, ct);
473:             return 1;
474:         }
475:         // No target vowel: if at start or no vowels, enter literal
476:         enterLiteral(s);
477:         appendSpan(s, ch, 0, 0, flags | 0x02);
478:         return 1;
479:     }
480: 
481:     // ── Tone marks: s, f, r, x, j ──
482:     if (lo == 's' or lo == 'f' or lo == 'r' or lo == 'x' or lo == 'j') {
483:         const r = computeRegions(s);
484:         if (r.has_nucleus) {
485:             const ct = currentTone(s);
486:             if (ct == lo) {
487:                 // Cancellation: same tone pressed again → strip tone, enter literal
488:                 enterLiteral(s);
489:                 appendSpan(s, ch, 0, 0, flags | 0x02);
490:                 return 1;
491:             }
492:             applyTone(s, lo);
493:             return 1;
494:         }
495:         // No nucleus vowels: treat as consonant
496:         appendSpan(s, ch, 0, 0, flags);
497:         return 1;
498:     }
499: 
500:     // ── z: tone reset or literal ──
501:     if (lo == 'z') {
502:         const ct = currentTone(s);
503:         if (ct != 0) {
504:             // Remove tone from all vowels
505:             var i: u8 = 0;
506:             while (i < s.len) : (i += 1) {
507:                 if (spanIsVowel(s.spans[i])) {
508:                     s.spans[i].tone = 0;
509:                 }
510:             }
511:             return 1;
512:         }
513:         // No tone to reset → enter literal
514:         enterLiteral(s);
515:         appendSpan(s, ch, 0, 0, flags | 0x02);
516:         return 1;
517:     }
518: 
519:     // ── Vowels ──
520:     if (isVowel(lo)) {
521:         appendSpan(s, ch, 0, 0, flags);
522:         // Re-apply tone placement after adding a vowel
523:         const ct = currentTone(s);
524:         if (ct != 0) applyTone(s, ct);
525:         return 1;
526:     }
527: 
528:     // ── Consonants ──
529:     appendSpan(s, ch, 0, 0, flags);
530:     autoFillUO(s);
531:     return 1;
532: }
